VALUES
  ('public-health-specialist-moex-00447', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '檢驗工具的敏感度（sensitivity）越高，勢必有以下何者特點？', '["特異度（specificity）越低", "偽陰性率越低", "陽性預測值越低", "陰性預測值越低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00448', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '以下關於疾病發生率（incidence）的描述，何者不恰當？', '["研究族群必須是有機會發病（atriskofdisease）的人", "研究族群沒有失去追蹤才可估計累積發生率（cumulativeincidence）", "發生密度的分母是有機會發病的累積人時（person-time）", "發生率維持大於零，盛行率（prevalence）就會逐漸上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00449', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某隨機分派試驗探討飲用蔓越莓汁是否降低尿道感染症。在 24 週的介入研究後，研究者發 現，每日飲用蔓越莓汁組的年化（annualized）泌尿道感染發生密度為0.48，飲用安慰劑飲品 組的年化泌尿道感染發生密度為0.75。根據這些資訊，以下推論何者最適合？', '["每日飲用蔓越莓汁3.7年可預防1次泌尿道感染", "蔓越莓汁組發生泌尿道感染的風險是安慰劑組的0.5倍", "每日飲用蔓越莓汁預防泌尿道感染的成效（efficacy）是56%", "每日飲用蔓越莓汁可降低27%的泌尿道感染風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00450', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列關於測量誤差（measurementerror）與資訊偏差（informationbias）的描述中，何者正確？', '["樣本數小會增加相關性估計值的測量誤差", "「適應症干擾」（confoundingbyindication）是資訊偏差的一種", "錯誤分組會高估因果相關性的估計值", "測量誤差是資訊偏差的充分條件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00451', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '報載：「過去數十年來，青少年第二型糖尿病的發生率逐年上升」。其實，在下結論之前，必 須確定各年之間的數據在方法學上可比較。以下幾個方法學上的考量，何者在此主題中比較 不重要？', '["歷年的第二型糖尿病檢驗方法與診斷標準是否一致", "各年數據是否有作年齡標準化", "各次調查之間的抽樣方法是否有改變過", "青少年的年齡定義在各次調查之間是否維持一樣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00452', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某國針對運輸業勞工進行的調查發現，在男性勞工中，工時越長者，身體質量指數越高，販 賣機上購買冷飲與零食的頻率也越高。而在女性勞工中，工時與身體質量指數或在販賣機上 購買冷飲與零食的頻率都無顯著相關。根據以上描述，以下推論何者正確？', '["職業干擾（confounds）工時與身體質量指數的相關性", "性別修飾（modifies）工時與販賣機消費行為頻率的相關性", "勞工的販賣機消費行為中介（mediates）工時與身體質量指數的相關性", "勞工的工時與販賣機消費行為對身體質量指數的影響有協同作用（synergy）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00453', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '英國千禧世代研究指出，青少年輕生意圖（suicidalattempt）與家長失業以及青少年本身的性 傾向有關。該研究以家長沒有失業的異性戀青少年作為對照組，比較以下三組青少年的輕生 意圖相對風險（relativerisk,RR）：家長沒有失業的性少數青少年（RR=2.92）、兩位家長都失 業的異性戀青少年（RR=2.34）、兩位家長都失業的性少數青少年（RR=7.41）。根據以上描述， 暫不論估計值的信賴區間，下列推論何者正確？', '["性少數青少年的輕生意圖是異性戀青少年的2.92倍", "雙親失業的家庭處境會增加青少年輕生意圖2.34倍", "性少數身分跟雙親失業的家庭處境對青少年的輕生意圖可能有協同式（synergistic）交互作 用的影響", "性少數身分跟雙親失業的家庭處境對青少年的輕生意圖可能有拮抗式（antagonistic）交互 作用的影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00454', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '藉由測量舒張壓與收縮壓，當二者之一超過標準則診斷為高血壓。這樣的篩檢方法稱為：', '["系列篩檢，可增加篩檢敏感度", "系列篩檢，可提高篩檢特異度", "平行篩檢，可提高篩檢敏感度", "平行篩檢，可提高篩檢特異度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00455', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在社區中以觀察式研究設計，藉由比較猴痘感染者與一般民眾的減毒天花疫苗接種率，可分 析該疫苗預防猴痘的效果。某研究以英國在2022年七月到十月間的猴痘確診案例中，以自我 認同為男同性戀、雙性戀與男同性性行為者的成年確診案例作為病例組，以下選項中何者比 較適合作為對照組？', '["同地區中已接種該疫苗的全體成年健康族群", "同地區中未接種該疫苗的全體成年健康族群", "同地區中未接種該疫苗的成年男同性戀、雙性戀與男同性性行為者", "同地區中未感染猴痘的成年男同性戀、雙性戀與男同性性行為者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00456', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某衛生單位利用多重管道宣傳一項社區營養服務。該衛生單位想了解那一個宣傳管道能有效 吸引民眾參與此社區營養服務，於是在參與該服務的民眾中進行隨機抽樣，調查參與者曾從 何處得知此健康服務的消息。從所有場次所收集到的966份問卷中，發現48%曾從親友介紹 得知此服務的消息、62%從活動當天里長廣播得知消息、31%從社區傳單與海報得知消息、 15%從相關新聞報導中得知消息（這四個管道選項可以複選）。根據上列數據，以下推論何者 最恰當？', '["四種宣傳策略相比，里長廣播是宣傳效果最高的管道", "里長廣播的宣傳效果是傳單海報的兩倍", "如果可以進一步交叉比對，則可進一步分析各宣傳管道是否有加成效果", "本數據無法直接分析宣傳效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
